data.content:
  1→/**
  2→ * Playback storage — save/load/list playbacks as JSON files.
  3→ * Storage: ~/.claude/playbacks/<uuid>.json
  4→ */
  5→
  6→import fs from 'fs';
  7→import path from 'path';
  8→import os from 'os';
  9→import crypto from 'crypto';
 10→
 11→const PLAYBACKS_DIR = path.join(os.homedir(), '.claude', 'playbacks');
 12→
 13→function ensureDir() {
 14→  if (!fs.existsSync(PLAYBACKS_DIR)) {
 15→    fs.mkdirSync(PLAYBACKS_DIR, { recursive: true });
 16→  }
 17→}
 18→
 19→/**
 20→ * Create a new playback from extracted events.
 21→ * @param {object} opts
 22→ * @param {string} opts.title
 23→ * @param {object[]} opts.sources - Source descriptors [{type, id?, project?, agents?}]
 24→ * @param {object[]} opts.events - Normalized events from extractors
 25→ * @param {string} opts.start - ISO timestamp
 26→ * @param {string} opts.end - ISO timestamp
 27→ * @returns {object} Saved playback metadata
 28→ */
 29→export function createPlayback({ title, sources, events, start, end, agents, tags }) {
 30→  ensureDir();
 31→
 32→  // Sort events by timestamp
 33→  events.sort((a, b) => a.ts - b.ts);
 34→
 35→  // Compute relative timestamps (t) from the earliest event
 36→  const baseTs = events.length > 0 ? events[0].ts : 0;
 37→  const normalized = events.map(e => ({
 38→    t: e.ts - baseTs,
 39→    type: e.type,
 40→    source: e.source,
 41→    sourceId: e.sourceId,
 42→    data: e.data,
 43→  }));
 44→
 45→  const id = crypto.randomUUID();
 46→  const durationMs = events.length > 0 ? events[events.length - 1].ts - events[0].ts : 0;
 47→
 48→  const playback = {
 49→    id,
 50→    version: 1,
 51→    title: title || 'Untitled playback',
 52→    created: new Date().toISOString(),
 53→    sources,
 54→    time_range: {
 55→      start: start || (events.length > 0 ? new Date(events[0].ts).toISOString() : null),
 56→      end: end || (events.length > 0 ? new Date(events[events.length - 1].ts).toISOString() : null),
 57→    },
 58→    duration_ms: durationMs,
 59→    edits: [],
 60→    tags: tags || [],
 61→    agents: agents || [],
 62→    events: normalized,
 63→  };
 64→
 65→  const filePath = path.join(PLAYBACKS_DIR, `${id}.json`);
 66→  fs.writeFileSync(filePath, JSON.stringify(playback, null, 2));
 67→
 68→  return {
 69→    id,
 70→    title: playback.title,
 71→    event_count: normalized.length,
 72→    duration_ms: durationMs,
 73→    sources: sources.length,
 74→  };
 75→}
 76→
 77→/**
 78→ * Get a playback by ID.
 79→ * @param {string} id
 80→ * @param {string} format - "full", "summary", "events_only"
 81→ */
 82→export function getPlayback(id, format = 'full') {
 83→  const filePath = path.join(PLAYBACKS_DIR, `${id}.json`);
 84→  if (!fs.existsSync(filePath)) return null;
 85→
 86→  const playback = JSON.parse(fs.readFileSync(filePath, 'utf8'));
 87→
 88→  if (format === 'summary') {
 89→    // Event counts by type
 90→    const counts = {};
 91→    for (const e of playback.events) {
 92→      counts[e.type] = (counts[e.type] || 0) + 1;
 93→    }
 94→    return {
 95→      id: playback.id,
 96→      title: playback.title,
 97→      created: playback.created,
 98→      sources: playback.sources,
 99→      time_range: playback.time_range,
100→      duration_ms: playback.duration_ms,
101→      event_count: playback.events.length,
102→      event_types: counts,
103→      edits: playback.edits.length,
104→    };
105→  }
106→
107→  if (format === 'events_only') {
108→    return { id: playback.id, events: playback.events };
109→  }
110→
111→  return playback;
112→}
113→
114→/**
115→ * List all playbacks, optionally filtered.
116→ */
117→export function listPlaybacks({ project, agent, tag, limit = 50 } = {}) {
118→  ensureDir();
119→
120→  const files = fs.readdirSync(PLAYBACKS_DIR).filter(f => f.endsWith('.json'));
121→  const playbacks = [];
122→
123→  for (const file of files) {
124→    try {
125→      const fp = path.join(PLAYBACKS_DIR, file);
126→      const raw = fs.readFileSync(fp, 'utf8');
127→      const pb = JSON.parse(raw);
128→
129→      // Filter by project
130→      if (project && !pb.sources.some(s => s.project === project || s.id === project)) continue;
131→      // Filter by agent
132→      if (agent && !pb.sources.some(s => s.agents?.includes(agent) || s.id === agent)) continue;
133→      // Filter by tag
134→      if (tag && !(pb.tags || []).includes(tag)) continue;
135→
136→      // Event counts by type
137→      const counts = {};
138→      for (const e of pb.events) {
139→        counts[e.type] = (counts[e.type] || 0) + 1;
140→      }
141→
142→      playbacks.push({
143→        id: pb.id,
144→        title: pb.title,
145→        created: pb.created,
146→        duration_ms: pb.duration_ms,
147→        event_count: pb.events.length,
148→        event_types: counts,
149→        sources: pb.sources,
150→        tags: pb.tags || [],
151→      });
152→    } catch { continue; }
153→  }
154→
155→  // Sort by created date, newest first
156→  playbacks.sort((a, b) => new Date(b.created) - new Date(a.created));
157→  return playbacks.slice(0, limit);
158→}
159→
160→/**
161→ * Apply edit operations to a playback.
162→ * @param {string} id
163→ * @param {object[]} operations - [{op: "trim"|"annotate"|"speed", ...}]
164→ */
165→export function editPlayback(id, operations) {
166→  const filePath = path.join(PLAYBACKS_DIR, `${id}.json`);
167→  if (!fs.existsSync(filePath)) return null;
168→
169→  const playback = JSON.parse(fs.readFileSync(filePath, 'utf8'));
170→
171→  for (const op of operations) {
172→    playback.edits.push(op);
173→
174→    if (op.op === 'annotate') {
175→      // Insert a marker event at the specified time
176→      playback.events.push({
177→        t: op.t,
178→        type: 'marker',
179→        source: 'editorial',
180→        data: { text: op.text, style: op.style || 'note' },
181→      });
182→      playback.events.sort((a, b) => a.t - b.t);
183→    }
184→    if (op.op === 'layout') {
185→      // Insert a layout event — player applies it via innerDv.fromJSON
186→      playback.events.push({
187→        t: op.t,
188→        type: 'layout',
189→        source: 'editorial',
190→        data: op.layout,
191→      });
192→      playback.events.sort((a, b) => a.t - b.t);
193→    }
194→    // trim and speed are render-time operations — stored in edits, applied by the player
195→  }
196→
197→  fs.writeFileSync(filePath, JSON.stringify(playback, null, 2));
198→
199→  return {
200→    id: playback.id,
201→    edit_count: playback.edits.length,
202→    event_count: playback.events.length,
203→  };
204→}
205→
206→/**
207→ * Create a trimmed copy of a playback (excerpt).
208→ * @param {string} id - Source playback ID
209→ * @param {object} opts
210→ * @param {number} opts.startT - Start time (ms from playback start)
211→ * @param {number} opts.endT - End time (ms from playback start)
212→ * @param {string} opts.title - Title for the excerpt
213→ * @param {string[]} opts.tags - Tags for the excerpt
214→ */
215→export function trimCopy(id, { startT, endT, title, tags }) {
216→  const source = getPlayback(id);
217→  if (!source) return null;
218→
219→  const trimmed = source.events.filter(e => e.t >= startT && e.t <= endT);
220→  const baseT = trimmed.length > 0 ? trimmed[0].t : 0;
221→  const rebaseEvents = trimmed.map(e => ({ ...e, t: e.t - baseT }));
222→  const durationMs = rebaseEvents.length > 0 ? rebaseEvents[rebaseEvents.length - 1].t : 0;
223→
224→  const baseMs = source.time_range?.start ? new Date(source.time_range.start).getTime() : 0;
225→
226→  const newId = crypto.randomUUID();
227→  const excerpt = {
228→    id: newId,
229→    version: 1,
230→    title: title || `Excerpt from ${source.title}`,
231→    created: new Date().toISOString(),
232→    sources: [...source.sources, { type: 'excerpt', parent: id, startT, endT }],
233→    time_range: {
234→      start: new Date(baseMs + startT).toISOString(),
235→      end: new Date(baseMs + endT).toISOString(),
236→    },
237→    duration_ms: durationMs,
238→    edits: [],
239→    tags: tags || [],
240→    agents: source.agents || [],
241→    events: rebaseEvents,
242→  };
243→
244→  ensureDir();
245→  const filePath = path.join(PLAYBACKS_DIR, `${newId}.json`);
246→  fs.writeFileSync(filePath, JSON.stringify(excerpt, null, 2));
247→
248→  return {
249→    id: newId,
250→    title: excerpt.title,
251→    event_count: rebaseEvents.length,
252→    duration_ms: durationMs,
253→    parent: id,
254→  };
255→}
256→

2356→const playbackCtrl = {
2357→  active: false,        // is a playback loaded and driving widgets?
2358→  playback: null,       // the full playback object
2359→  currentT: 0,          // current playback time (ms from start)
2360→  playing: false,
2361→  speed: 1,
2362→  cinematic: true,      // always stream assistant text char-by-char
2363→  // Derived state for widgets — built from events up to currentT
2364→  // Mimics the shape of live `state.messages` so chat widget can render it
2365→  synthState: null,
2366→  listeners: new Set(),  // widgets that want playback updates
2367→
2368→  load(pb) {
2369→    this.playback = pb
2370→    this.currentT = 0
2371→    this.playing = false
2372→    this.active = true
2373→    this._resetCache()
2374→    this.buildSynthState()
2375→    this.notify()
2376→  },
2377→
2378→  unload() {
2379→    this.active = false
2380→    this.playback = null
2381→    this.synthState = null
2382→    this.notify()
2383→  },
2384→
2385→  // Incremental scan cache — avoids re-scanning all events from 0 on every tick
2386→  _cache: null, // { lastT, lastIdx, messages, agentSet, nameMap }
2387→
2388→  _resetCache() {
2389→    this._cache = null
2390→  },
2391→
2392→  // Build a synthetic state object from events up to currentT
2393→  // Shape matches what updateChatWidget expects: { messages: [...], agents: [...] }
2394→  buildSynthState() {
2395→    if (!this.playback) { this.synthState = null; return }
2396→    const events = this.playback.events
2397→
2398→    // If scrubbing backward, reset cache
2399→    if (this._cache && this.currentT < this._cache.lastT) {
2400→      this._cache = null
2401→    }
2402→
2403→    let messages, agentSet, nameMap, startIdx
2404→    if (this._cache) {
2405→      // Resume from cache — reuse array, truncate to committed length
2406→      messages = this._cache.messages
2407→      messages.length = this._cache.committedLen
2408→      agentSet = this._cache.agentSet
2409→      nameMap = this._cache.nameMap
2410→      startIdx = this._cache.lastIdx
2411→    } else {
2412→      messages = []
2413→      agentSet = new Map()
2414→      nameMap = new Map()
2415→      // Seed from recording's agent snapshot if present
2416→      for (const a of (this.playback.agents || [])) {
2417→        if (a.id) nameMap.set(a.id, { friendly_name: a.friendly_name, labels: a.labels || [] })
2418→      }
2419→      startIdx = 0
2420→    }
2421→
2422→    let typing = null    // { text, to } currently being "typed" in input box (cinematic)
2423→    let interrupt = false
2424→    let currentEdit = this._cache?.currentEdit || null // most recent Edit tool call (for code panel)
2425→    const currentState = window._lastState
2426→    const baseMs = this.playback.time_range?.start ? new Date(this.playback.time_range.start).getTime() : 0
2427→    const mkTs = (t) => new Date(baseMs + t).toISOString()
2428→
2429→    // Max lookahead for cinematic typing animation (typing starts before the event timestamp)
2430→    const typingLookahead = this.cinematic ? 5000 : 0
2431→
2432→    let cacheIdx = startIdx
2433→    for (let i = startIdx; i < events.length; i++) {
2434→      const ev = events[i]
2435→      if (ev.t > this.currentT + typingLookahead) break
2436→      cacheIdx = i + 1
2437→
2438→      // Track edits for code panel — no time gate, because the lookahead
2439→      // consumes events past currentT for typing animation. Edit tracking
2440→      // must happen here or the cache will skip past the event. The code
2441→      // widget uses edit.t vs currentT for reveal timing.
2442→      if (ev.type === 'tool_call') {
2443→        const tn = ev.data.tool
2444→        const ti = ev.data.input || {}
2445→        if (tn === 'Edit' || tn === 'edit') {
2446→          currentEdit = { file: ti.file_path, old: ti.old_string, new: ti.new_string, t: ev.t, _evT: mkTs(ev.t) }
2447→        } else if (tn === 'Write' || tn === 'write') {
2448→          currentEdit = { file: ti.file_path, old: null, new: ti.content, t: ev.t, _evT: mkTs(ev.t) }
2449→        }
2450→      }
2451→
2452→      if (ev.type === 'chat' || ev.type === 'delegate') {
2453→        const from = ev.data.from || 'system'
2454→        const to = ev.data.to || 'system'
2455→        const text = ev.type === 'delegate' ? `**delegate**: ${ev.data.description || ''}\n${ev.data.text || ''}` : (ev.data.text || '')
2456→        const userAliases = ['web', 'skip', 'human', 'user']
2457→        const isFromUser = userAliases.includes(from)
2458→
2459→        // Cinematic typing for user chat messages
2460→        if (this.cinematic && isFromUser && ev.type === 'chat' && text.length > 0) {
2461→          const minTypingMs = 1500
2462→          const typingRate = 0.06
2463→          const naturalDur = text.length / typingRate
2464→          const typingDur = Math.max(naturalDur, minTypingMs)
2465→          const typingStart = ev.t - typingDur
2466→          const sendDelay = 300
2467→          if (this.currentT >= ev.t + sendDelay) {
2468→            messages.push({ _evType: ev.type, from, to, text, timestamp: mkTs(ev.t) })
2469→          } else if (this.currentT >= typingStart) {
2470→            const elapsed = this.currentT - typingStart
2471→            const charRate = text.length / typingDur
2472→            const revealed = Math.floor(elapsed * charRate)
2473→            typing = { text: text.slice(0, Math.min(revealed, text.length)), to }
2474→          }
2475→          // else: event is in the future and typing hasn't started — skip
2476→        } else if (ev.t <= this.currentT) {
2477→          messages.push({ _evType: ev.type, from, to, text, timestamp: mkTs(ev.t) })
2478→        }
2479→        if (ev.t <= this.currentT) {
