/* Playback focus/frost — director's narration on non-focus panels */
.pb-dockview .dv-view-container { position: relative; }
.pb-frost-overlay {
  position: absolute; inset: 0; z-index: 50;
  backdrop-filter: blur(4px);
  background: rgba(0, 0, 0, 0.35);
  display: flex; align-items: center; justify-content: center;
  transition: opacity 0.4s ease;
  cursor: pointer;
}
.pb-frost-overlay.has-narration { cursor: default; }
.pb-frost-narration {
  max-width: 80%; padding: 16px 24px;
  color: #e0e0e0; font-size: 15px; line-height: 1.6;
  text-align: center; font-style: italic;
  text-shadow: 0 1px 3px rgba(0,0,0,0.5);
}
.pb-frost-overlay.defrosting { opacity: 0; pointer-events: none; }
.pb-narration-subtitle {
  position: absolute; bottom: 0; left: 0; right: 0;
  padding: 8px 16px; text-align: center;
  background: rgba(0, 0, 0, 0.7); color: #e0e0e0;
  font-size: 13px; font-style: italic; line-height: 1.5;
  z-index: 60; transition: opacity 0.3s ease;
  backdrop-filter: blur(2px);
}
.pb-narration-subtitle.hidden { opacity: 0; pointer-events: none; }

