// --- Focus/frost system ---
const subtitleEl = container.querySelector('.pb-narration-subtitle')
let _currentFocusPanel = null  // currently focused panel name, null = no focus
let _defrostedPanels = new Set()  // panels the user has manually defrosted
let _narrationOnSubtitle = false  // narration pushed to subtitle bar

function applyFocusState(focusEvent) {
  const focusPanel = focusEvent?.data?.panel || null
  const narration = focusEvent?.data?.narration || ''

  // New focus event — reset defrosts
  if (focusPanel !== _currentFocusPanel) {
    _defrostedPanels.clear()
    _narrationOnSubtitle = false
    _currentFocusPanel = focusPanel
  }

  // Remove all existing frost overlays
  for (const overlay of container.querySelectorAll('.pb-frost-overlay')) {
    overlay.remove()
  }
  subtitleEl.classList.add('hidden')
  subtitleEl.textContent = ''

  if (!focusPanel) return  // no active focus — all clear

  // Find the largest non-focus panel for narration
  let narrationPanel = null
  let narrationPanelArea = 0

  for (const panel of innerDv.panels) {
    const component = panel.api.component
    const el = panel.view?.content?.element
    if (!el) continue
    const viewContainer = el.closest('.dv-view-container') || el.parentElement
    if (!viewContainer) continue

    if (component === focusPanel) continue  // skip the focus panel
    if (_defrostedPanels.has(component)) continue  // user defrosted this one

    const rect = viewContainer.getBoundingClientRect()
    if (rect.width * rect.height > narrationPanelArea) {
      narrationPanelArea = rect.width * rect.height
      narrationPanel = component
    }
  }

  // Apply frost overlays to non-focus panels
  for (const panel of innerDv.panels) {
    const component = panel.api.component
    const el = panel.view?.content?.element
    if (!el) continue
    if (component === focusPanel) continue
    if (_defrostedPanels.has(component)) continue

    const viewContainer = el.closest('.dv-view-container') || el.parentElement
    if (!viewContainer) continue
    // Ensure relative positioning for overlay
    if (getComputedStyle(viewContainer).position === 'static') {
      viewContainer.style.position = 'relative'
    }

    const overlay = document.createElement('div')
    overlay.className = 'pb-frost-overlay'

    // Put narration on the largest non-focus panel
    if (component === narrationPanel && narration && !_narrationOnSubtitle) {
      overlay.classList.add('has-narration')
      const narDiv = document.createElement('div')
      narDiv.className = 'pb-frost-narration'
      narDiv.textContent = narration
      overlay.appendChild(narDiv)
    }

    // Click to defrost — narration falls to subtitle
    overlay.addEventListener('click', () => {
      _defrostedPanels.add(component)
      overlay.classList.add('defrosting')
      setTimeout(() => overlay.remove(), 400)
      // If this panel had narration, move it to subtitle bar
      if (component === narrationPanel && narration) {
        _narrationOnSubtitle = true
        subtitleEl.textContent = narration
        subtitleEl.classList.remove('hidden')
      }
    })

    viewContainer.appendChild(overlay)
  }

  // If narration is on subtitle (user defrosted), show it there
  if (_narrationOnSubtitle && narration) {
    subtitleEl.textContent = narration
    subtitleEl.classList.remove('hidden')
  }
}

