const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.launch();
  const page = await browser.newPage();

  page.on('console', msg => console.log('CONSOLE:', msg.type(), msg.text()));
  page.on('pageerror', err => console.log('PAGE ERROR:', err.message));

  await page.goto('http://localhost:5199');
  await page.waitForTimeout(2000);

  // Check if playback widget exists
  const pbWidget = await page.\$('.playback-widget');
  console.log('Playback widget found:', !!pbWidget);

  // Try to load the Identity Crisis playback via the search
  const searchInput = await page.\$('.pb-search');
  if (searchInput) {
    await searchInput.click();
    await page.waitForTimeout(500);
    await searchInput.fill('Identity');
    await page.waitForTimeout(500);

    // Check dropdown
    const dropdown = await page.\$('.pb-dropdown');
    const dropdownVisible = await dropdown?.isVisible();
    console.log('Dropdown visible:', dropdownVisible);
    const dropdownHTML = await dropdown?.innerHTML();
    console.log('Dropdown content:', dropdownHTML?.substring(0, 300));

    // Click first result
    const firstResult = await page.\$('.pb-dropdown .pb-item');
    if (firstResult) {
      await firstResult.click();
      await page.waitForTimeout(1000);
    }
  }

  // Check for frost overlays
  const frostOverlays = await page.\$\$('.pb-frost-overlay');
  console.log('Frost overlays:', frostOverlays.length);

  // Check inner dockview panels  
  const panels = await page.\$\$('.pb-dockview .dv-view-container');
  console.log('Inner DV panels:', panels.length);

  // Check playback state
  const pbState = await page.evaluate(() => {
    const ctrl = window._playbackCtrl;
    return {
      active: ctrl?.active,
      currentT: ctrl?.currentT,
      eventCount: ctrl?.playback?.events?.length,
      focusEvents: ctrl?.playback?.events?.filter(e => e.type === 'focus')?.length
    };
  });
  console.log('Playback state:', JSON.stringify(pbState));

  // Take screenshot
  await page.screenshot({ path: '/tmp/playback-debug.png', fullPage: true });
  console.log('Screenshot saved to /tmp/playback-debug.png');

  await browser.close();
})().catch(e => console.error('ERROR:', e.message));
