import fs from 'fs';
const pb = JSON.parse(fs.readFileSync(process.env.HOME + '/.claude/playbacks/d0f23861-0263-48b7-af7d-0d6dd5404438.json', 'utf8'));

// Key phrases to find act boundaries
const markers = [
  'killed', 'kitty', 'identity', 'detectSession', 'markRead', 'message theft',
  'spawn', 'scribe', 'documentarian', 'playback', 'frost', 'narration',
  'omg dude', 'fresh\'s shit', 'activity cards', 'showing up',
  'session_ids', 'merge', 'contamination', 'set-not-merge', 'ghost',
  'sessionFromRoster', 'roster breadcrumb', 'MCP restart',
  'movie', 'parents', 'watchable', 'making of'
];

const baseT = 0;
const hits = [];

for (const ev of pb.events) {
  const text = JSON.stringify(ev.data || '').toLowerCase();
  for (const m of markers) {
    if (text.includes(m.toLowerCase())) {
      const mins = (ev.t / 60000).toFixed(1);
      const edtHour = Math.floor(ev.t / 3600000);
      const edtMin = Math.floor((ev.t % 3600000) / 60000);
      const timeStr = `${edtHour}:${String(edtMin).padStart(2, '0')}`;
      hits.push({
        t: ev.t,
        mins,
        edt: timeStr,
        type: ev.type,
        source: ev.source || ev.sourceId || '',
        match: m,
        preview: (typeof ev.data === 'string' ? ev.data : JSON.stringify(ev.data)).slice(0, 120)
      });
      break; // one match per event
    }
  }
}

// Deduplicate by time bucket (1-minute windows)
const seen = new Set();
const deduped = hits.filter(h => {
  const bucket = Math.floor(h.t / 60000);
  const key = `${bucket}-${h.match}`;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

// Sort by time
deduped.sort((a, b) => a.t - b.t);

console.log(`Total events: ${pb.events.length}`);
console.log(`Key moments found: ${deduped.length}\n`);

for (const h of deduped) {
  console.log(`[${h.edt} EDT] (t=${h.mins}min) [${h.type}] match="${h.match}"`);
  console.log(`  ${h.preview}`);
  console.log();
}
