import fs from 'fs';
const pb = JSON.parse(fs.readFileSync(process.env.HOME + '/.claude/playbacks/d0f23861-0263-48b7-af7d-0d6dd5404438.json', 'utf8'));

// Find specific act boundary events
const boundaries = [
  { label: "ACT 1: Kitty killed / agents dead", patterns: ["killed", "kitty tabs"] },
  { label: "ACT 2: Identity swap / detectSession", patterns: ["fleet ID", "identity", "reassigned"] },
  { label: "ACT 3: markRead / message theft", patterns: ["markRead", "message theft", "messages disappearing"] },
  { label: "ACT 4: MCP restart / sessionFromRoster", patterns: ["MCP restart", "sessionFromRoster", "roster breadcrumb"] },
  { label: "MAKING-OF: Scribe spawned", patterns: ["documentarian", "spawn.*scribe", "scribe"] },
  { label: "MAKING-OF: Playback built", patterns: ["369-event", "playback created", "five acts"] },
  { label: "MAKING-OF: Movie request", patterns: ["parents", "movie", "watchable"] },
  { label: "MAKING-OF: Frost system", patterns: ["frost", "narration"] },
  { label: "ACT 5: Ghost reveal", patterns: ["omg dude", "fresh's shit", "activity cards.*showing"] },
  { label: "ACT 5: Set-not-merge fix", patterns: ["session_ids", "accumulating", "set.*instead"] },
];

for (const b of boundaries) {
  let found = false;
  for (const ev of pb.events) {
    const text = JSON.stringify(ev.data || '').toLowerCase();
    for (const p of b.patterns) {
      if (text.match(new RegExp(p, 'i'))) {
        const mins = (ev.t / 60000).toFixed(1);
        const h = Math.floor(ev.t / 3600000);
        const m = Math.floor((ev.t % 3600000) / 60000);
        const preview = (typeof ev.data === 'string' ? ev.data : JSON.stringify(ev.data)).slice(0, 150);
        console.log(`\n${b.label}`);
        console.log(`  t=${ev.t}ms (${mins}min = ${h}:${String(m).padStart(2,'0')} from start)`);
        console.log(`  type=${ev.type} source=${ev.sourceId || ev.source}`);
        console.log(`  ${preview}`);
        found = true;
        break;
      }
    }
    if (found) break;
  }
  if (!found) console.log(`\n${b.label}\n  NOT FOUND`);
}

// Also find first and last events by each source
console.log('\n\n--- Source activity ranges ---');
const sources = {};
for (const ev of pb.events) {
  const src = ev.sourceId || ev.source || 'unknown';
  if (!sources[src]) sources[src] = { first: ev.t, last: ev.t, count: 0 };
  sources[src].last = ev.t;
  sources[src].count++;
}
for (const [src, s] of Object.entries(sources)) {
  const f = (s.first / 60000).toFixed(1);
  const l = (s.last / 60000).toFixed(1);
  console.log(`  ${src}: ${f}min – ${l}min (${s.count} events)`);
}

// Find the big gaps (>5 min with no events)
console.log('\n--- Dead zones (>5min gaps) ---');
const sorted = [...pb.events].sort((a,b) => a.t - b.t);
for (let i = 1; i < sorted.length; i++) {
  const gap = sorted[i].t - sorted[i-1].t;
  if (gap > 300000) {
    const startMin = (sorted[i-1].t / 60000).toFixed(1);
    const endMin = (sorted[i].t / 60000).toFixed(1);
    console.log(`  ${startMin}min – ${endMin}min (${(gap/60000).toFixed(1)}min gap)`);
  }
}
